const svg = $('#def-svg'), slider = $('#def-y'), yv = $('#def-yv');
const W=620,H=260, pad={l:55,r:20,t:20,b:40};
const xmin=0.02, xmax=2.0;
const ymin=0.0, ymax=6.0;
const X = x => pad.l + (x-xmin)/(xmax-xmin)*(W-pad.l-pad.r);
const Y = v => H - pad.b - (v-ymin)/(ymax-ymin)*(H-pad.t-pad.b);

function thetaReal(y){
  // 1 + 2 sum_{n>=1} exp(-pi n^2 y)
  let s = 1.0;
  for(let n=1;n<=200;n++){
    const t = Math.exp(-Math.PI*n*n*y);
    if(t < 1e-14) break;
    s += 2*t;
  }
  return s;
}

function render(){
  svg.innerHTML='';
  // axes
  const ax = SVG('line',{x1:pad.l,y1:Y(0),x2:W-pad.r,y2:Y(0),stroke:'var(--line)','stroke-width':1});
  const ay = SVG('line',{x1:pad.l,y1:pad.t,x2:pad.l,y2:H-pad.b,stroke:'var(--line)','stroke-width':1});
  svg.appendChild(ax); svg.appendChild(ay);
  // y ticks
  for(let v=1; v<=6; v++){
    const y = Y(v);
    svg.appendChild(SVG('line',{x1:pad.l-4,y1:y,x2:pad.l,y2:y,stroke:'var(--mute)'}));
    const t = SVG('text',{x:pad.l-8,y:y+4,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
    t.textContent = v;
    svg.appendChild(t);
  }
  // x ticks
  for(const xv of [0.1,0.5,1.0,1.5,2.0]){
    const x = X(xv);
    svg.appendChild(SVG('line',{x1:x,y1:Y(0),x2:x,y2:Y(0)+4,stroke:'var(--mute)'}));
    const t = SVG('text',{x,y:Y(0)+16,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    t.textContent = xv;
    svg.appendChild(t);
  }
  // labels
  const xl = SVG('text',{x:(W+pad.l-pad.r)/2, y:H-8, 'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
  xl.textContent = 'y'; svg.appendChild(xl);
  const yl = SVG('text',{x:16, y:(H+pad.t-pad.b)/2, 'text-anchor':'middle','font-size':12,fill:'var(--mute)',transform:`rotate(-90 16 ${(H+pad.t-pad.b)/2})`});
  yl.textContent = 'θ(iy)'; svg.appendChild(yl);

  // theta curve
  const pts = [];
  const N = 240;
  for(let i=0;i<=N;i++){
    const xv = xmin + (xmax-xmin)*i/N;
    const yv = thetaReal(xv);
    pts.push([X(xv), Y(Math.min(yv, ymax+1))]);
  }
  const d = pts.map((p,i)=>(i?'L':'M')+p[0].toFixed(1)+' '+p[1].toFixed(1)).join(' ');
  svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--blue)','stroke-width':2}));

  // asymptote y=1
  const y1 = Y(1);
  svg.appendChild(SVG('line',{x1:pad.l,y1,x2:W-pad.r,y2:y1,stroke:'var(--green)','stroke-dasharray':'4 3','stroke-width':1}));
  const at = SVG('text',{x:W-pad.r-4, y:y1-4, 'text-anchor':'end','font-size':11,fill:'var(--green)'});
  at.textContent = 'θ → 1'; svg.appendChild(at);

  // marker for current y
  const yC = parseFloat(slider.value);
  const vC = thetaReal(yC);
  svg.appendChild(SVG('line',{x1:X(yC),y1:pad.t,x2:X(yC),y2:H-pad.b,stroke:'var(--yellow)','stroke-dasharray':'2 3'}));
  svg.appendChild(SVG('circle',{cx:X(yC),cy:Y(Math.min(vC,ymax+1)),r:4,fill:'var(--yellow)'}));
  const lab = SVG('text',{x:X(yC)+8, y:Y(Math.min(vC,ymax+1))-8,'font-size':12, fill:'var(--yellow)'});
  lab.textContent = `θ(i·${yC.toFixed(2)}) ≈ ${vC.toFixed(4)}`;
  svg.appendChild(lab);
  yv.textContent = `y = ${yC.toFixed(2)},  θ = ${vC.toFixed(5)}`;
}
slider.addEventListener('input', render);
render();

