  svg.appendChild(SVG('circle',{cx:X(yC),cy:Y(Math.min(vC,ymax+1)),r:4,fill:'var(--yellow)'}));
  const lab = SVG('text',{x:X(yC)+8, y:Y(Math.min(vC,ymax+1))-8,'font-size':12, fill:'var(--yellow)'});
  lab.textContent = `θ(i·${yC.toFixed(2)}) ≈ ${vC.toFixed(4)}`;
  svg.appendChild(lab);
  yv.textContent = `y = ${yC.toFixed(2)},  θ = ${vC.toFixed(5)}`;
}
slider.addEventListener('input', render);
render();

const svg = $('#qexp-svg');
const btns = $$('#w-qexp [data-k]');

// r_k(n): number of ways to write n as an ordered sum of k signed squares.
// Compute by convolving the theta sequence r1(n)=1 if n is a square (with sign multiplicity),
// actually r1 takes values 1 (n=0), 2 (n square >0), 0 else.
function makeRk(k, N){
  // build r1 up to N
  const r1 = new Array(N+1).fill(0);
  r1[0] = 1;
  for(let m=1; m*m<=N; m++) r1[m*m] = 2;
  // convolve k times
  let cur = r1.slice();
  for(let i=1;i<k;i++){
    const nxt = new Array(N+1).fill(0);
    for(let a=0;a<=N;a++){
      if(cur[a]===0) continue;
      for(let b=0;a+b<=N;b++){
        if(r1[b]===0) continue;
        nxt[a+b] += cur[a]*r1[b];
      }
    }
    cur = nxt;
  }
  return cur;
}

function render(k){
  svg.innerHTML = '';
  const W=620, H=270, pad={l:50,r:16,t:20,b:36};
  const Nmax = 40;
  const coeffs = makeRk(k, Nmax);
  // Use max over visible range
  let maxV = 1;
  for(let n=0;n<=Nmax;n++) if(coeffs[n]>maxV) maxV = coeffs[n];
  // log-ish scale when too big
  const useLog = maxV > 50;
  const scale = v => useLog ? Math.log(1+v) / Math.log(1+maxV) : v/maxV;

  const bw = (W - pad.l - pad.r) / (Nmax+1);
  // axes
  svg.appendChild(SVG('line',{x1:pad.l,y1:H-pad.b,x2:W-pad.r,y2:H-pad.b,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:pad.l,y1:pad.t,x2:pad.l,y2:H-pad.b,stroke:'var(--line)'}));

  // bars
  for(let n=0;n<=Nmax;n++){
    const v = coeffs[n];
    const h = v>0 ? Math.max(2, scale(v) * (H - pad.t - pad.b)) : 0;
    const x = pad.l + n*bw;
    const yTop = H - pad.b - h;
    if(h>0){
      svg.appendChild(SVG('rect',{x:x+1, y:yTop, width:Math.max(1,bw-2), height:h, fill:'var(--yellow)', opacity:0.85}));
    }
    if(n%5===0){
      const t = SVG('text',{x:x+bw/2, y:H-pad.b+14, 'text-anchor':'middle','font-size':10, fill:'var(--mute)'});
      t.textContent = n;
      svg.appendChild(t);
    }
    if(v>0 && n<=Nmax){
      const lbl = SVG('text',{x:x+bw/2, y:yTop-3, 'text-anchor':'middle','font-size':9, fill:'var(--ink)'});
      lbl.textContent = v;
      svg.appendChild(lbl);
    }
  }
  // axis labels
  const tx = SVG('text',{x:(W+pad.l-pad.r)/2, y:H-6,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
  tx.textContent = 'exponent index n  (term q^(n/2))'; svg.appendChild(tx);
  const ty = SVG('text',{x:16,y:(H+pad.t-pad.b)/2,'text-anchor':'middle','font-size':11,fill:'var(--mute)',transform:`rotate(-90 16 ${(H+pad.t-pad.b)/2})`});
  ty.textContent = useLog ? 'r_k(n) (log scale)' : 'r_k(n)';
  svg.appendChild(ty);

  // title tag
  const tt = SVG('text',{x:W-pad.r,y:pad.t+4, 'text-anchor':'end','font-size':12,fill:'var(--blue)','font-style':'italic'});
  tt.textContent = `θ^${k}`; svg.appendChild(tt);
}

btns.forEach(b=>b.addEventListener('click',()=>{
  btns.forEach(x=>x.classList.remove('active'));
  b.classList.add('active');
  render(parseInt(b.dataset.k,10));
}));
render(1);

