btns.forEach(b=>b.addEventListener('click',()=>{
  btns.forEach(x=>x.classList.remove('active'));
  b.classList.add('active');
  render(parseInt(b.dataset.k,10));
}));
render(1);

const svg = $('#trans-svg'), out = $('#trans-out');
const W=620,H=260, pad={l:55,r:20,t:20,b:40};

function thetaReal(y){
  let s = 1.0;
  for(let n=1;n<=200;n++){
    const t = Math.exp(-Math.PI*n*n*y);
    if(t<1e-14) break;
    s += 2*t;
  }
  return s;
}

const xmin=0.1, xmax=2.5;
// find max of both curves
let ymax = 0;
const N=220;
const ptsA=[], ptsB=[];
for(let i=0;i<=N;i++){
  const xv = xmin + (xmax-xmin)*i/N;
  const a = thetaReal(1/xv);         // θ(i/y)
  const b = Math.sqrt(xv)*thetaReal(xv); // √y · θ(iy)
  ptsA.push([xv,a]); ptsB.push([xv,b]);
  if(a>ymax) ymax=a; if(b>ymax) ymax=b;
}
ymax = Math.min(ymax, 8);

const X = x => pad.l + (x-xmin)/(xmax-xmin)*(W-pad.l-pad.r);
const Y = v => H - pad.b - (Math.min(v,ymax)/ymax)*(H-pad.t-pad.b);

// axes
svg.appendChild(SVG('line',{x1:pad.l,y1:H-pad.b,x2:W-pad.r,y2:H-pad.b,stroke:'var(--line)'}));
svg.appendChild(SVG('line',{x1:pad.l,y1:pad.t,x2:pad.l,y2:H-pad.b,stroke:'var(--line)'}));

// y-ticks
for(let v=1; v<=Math.floor(ymax); v++){
  const y = Y(v);
  svg.appendChild(SVG('line',{x1:pad.l-4,y1:y,x2:pad.l,y2:y,stroke:'var(--mute)'}));
  const t = SVG('text',{x:pad.l-8,y:y+4,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
  t.textContent = v; svg.appendChild(t);
}
// x-ticks
for(const xv of [0.5,1.0,1.5,2.0,2.5]){
  const x = X(xv);
  svg.appendChild(SVG('line',{x1:x,y1:H-pad.b,x2:x,y2:H-pad.b+4,stroke:'var(--mute)'}));
  const t = SVG('text',{x,y:H-pad.b+16,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
  t.textContent = xv; svg.appendChild(t);
}
// labels
const xl = SVG('text',{x:(W+pad.l-pad.r)/2, y:H-6, 'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
xl.textContent = 'y'; svg.appendChild(xl);

function pathOf(pts, color, dash){
  const d = pts.map((p,i)=>(i?'L':'M')+X(p[0]).toFixed(1)+' '+Y(p[1]).toFixed(1)).join(' ');
  const pth = SVG('path',{d,fill:'none',stroke:color,'stroke-width':2.2});
  if(dash) pth.setAttribute('stroke-dasharray', dash);
  svg.appendChild(pth);
}
pathOf(ptsA, 'var(--blue)');
pathOf(ptsB, 'var(--yellow)', '4 3');

// legend
const lg = SVG('g',{});
svg.appendChild(lg);
lg.appendChild(SVG('line',{x1:W-pad.r-180,y1:pad.t+14,x2:W-pad.r-150,y2:pad.t+14,stroke:'var(--blue)','stroke-width':2.2}));
const t1 = SVG('text',{x:W-pad.r-146,y:pad.t+18,'font-size':12,fill:'var(--ink)'}); t1.textContent='θ(i/y)';
lg.appendChild(t1);
const l2 = SVG('line',{x1:W-pad.r-180,y1:pad.t+32,x2:W-pad.r-150,y2:pad.t+32,stroke:'var(--yellow)','stroke-width':2.2,'stroke-dasharray':'4 3'});
lg.appendChild(l2);
const t2 = SVG('text',{x:W-pad.r-146,y:pad.t+36,'font-size':12,fill:'var(--ink)'}); t2.textContent='√y · θ(iy)';
lg.appendChild(t2);

// numeric check
const samples = [0.25,0.5,1.0,1.7];
let msg = 'spot check:\n';
for(const y of samples){
  const lhs = thetaReal(1/y);
  const rhs = Math.sqrt(y)*thetaReal(y);
  msg += `  y=${y.toFixed(2)}:  θ(i/y)=${lhs.toFixed(6)},  √y·θ(iy)=${rhs.toFixed(6)},  diff=${(lhs-rhs).toExponential(2)}\n`;
}
out.textContent = msg.trim();

