const input = $('#rk-n'), out = $('#rk-out'), hint = $('#rk-hint'), svg = $('#rk-svg');

function sigma(n){
  if(n<=0) return 0;
  let s=0;
  for(let d=1; d*d<=n; d++){
    if(n%d===0){ s+=d; if(d*d!==n) s+=n/d; }
  }
  return s;
}
function d_mod4(n){ // (d_1, d_3)
  let a=0,b=0;
  for(let d=1; d<=n; d++){
    if(n%d===0){
      if(d%4===1) a++;
      if(d%4===3) b++;
    }
  }
  return [a,b];
}
function r2(n){
  if(n===0) return 1;
  let c=0;
  const B = Math.floor(Math.sqrt(n));
  for(let a=-B; a<=B; a++){
    const rem = n - a*a;
    if(rem<0) continue;
    const b = Math.round(Math.sqrt(rem));
    if(b*b===rem) c += (b===0?1:2);
  }
  return c;
}
function r3(n){
  if(n===0) return 1;
  let c=0;
  const B = Math.floor(Math.sqrt(n));
  for(let a=-B; a<=B; a++){
    const r = n-a*a; if(r<0) continue;
    c += r2(r);
  }
  return c;
}
function r4(n){
  if(n===0) return 1;
  let c=0;
  const B = Math.floor(Math.sqrt(n));
  for(let a=-B; a<=B; a++){
    const r = n-a*a; if(r<0) continue;
    c += r3(r);
  }
  return c;
}

function render(){
  let n = parseInt(input.value,10);
  if(!Number.isFinite(n)) n = 0;
  n = Math.max(0, Math.min(50, n));
  input.value = n;

  const R2 = r2(n), R3 = r3(n), R4 = r4(n);
  const sig = sigma(n);
  const sigQ = (n%4===0) ? sigma(n/4) : 0;
  const rhs4 = 8*sig - 32*sigQ;
  const [d1,d3] = d_mod4(n);
  const rhs2 = 4*(d1 - d3);

  const lines = [];
  lines.push(`n = ${n}`);
  lines.push(`r_2(n) = ${R2}        4(d_1(n) - d_3(n)) = 4·(${d1} - ${d3}) = ${rhs2}     ${R2===rhs2?'OK':'DIFF'}`);
  lines.push(`r_3(n) = ${R3}        (no simple closed form;   Gauss genus theory gives one mod 8)`);
  lines.push(`r_4(n) = ${R4}        8σ(n) - 32σ(n/4)  = 8·${sig} - 32·${sigQ} = ${rhs4}     ${R4===rhs4?'OK':'DIFF'}`);
  if(n>0 && n%2===1) lines.push(`         (n odd ⇒ r_4(n) = 8σ(n) = ${8*sig})`);
  out.textContent = lines.join('\n');

  // small example hint
  if(n>0){
    hint.textContent = `try 25, 30, 32, 48 …`;
  } else {
    hint.textContent = `r_k(0) = 1 for all k (the all-zero tuple).`;
  }

  // r_8 by convolution using the small-n r2 table
  function r8(nn){
    if(nn===0) return 1;
    let c = 0;
    for(let a=0; a<=nn; a++){
      const b = nn-a;
      c += r4(a)*r4(b);
    }
    return c;
  }
  // draw bar chart across k=1,2,3,4,8
  svg.innerHTML = '';
  const W=620, H=180, pad={l:50,r:16,t:24,b:36};
  const kList = [1,2,3,4,8];
  const vals = [n===0?1:(n===1?2:0), R2, R3, R4, r8(n)];
  // k=1 value for given n: 2 if positive square, 1 if n=0, else 0
  if(n>0){
    const rt = Math.round(Math.sqrt(n));
    vals[0] = rt*rt===n ? 2 : 0;
  }
  const maxV = Math.max(1, ...vals);
  const scale = v => Math.log(1+v)/Math.log(1+maxV);
  const bw = (W-pad.l-pad.r)/kList.length;

  svg.appendChild(SVG('line',{x1:pad.l,y1:H-pad.b,x2:W-pad.r,y2:H-pad.b,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:pad.l,y1:pad.t,x2:pad.l,y2:H-pad.b,stroke:'var(--line)'}));

  const COLORS = ['var(--blue)','var(--yellow)','var(--green)','var(--cyan)','var(--violet)'];
  for(let i=0;i<kList.length;i++){
    const k = kList[i], v = vals[i];
    const x = pad.l + i*bw;
    const h = v>0 ? scale(v)*(H-pad.t-pad.b) : 0;
    if(h>0){
      svg.appendChild(SVG('rect',{x:x+bw*0.2, y:H-pad.b-h, width:bw*0.6, height:h, fill:COLORS[i], opacity:0.9}));
    }
    const lab = SVG('text',{x:x+bw/2,y:H-pad.b+18,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
    lab.textContent = 'k=' + k; svg.appendChild(lab);
    const vlab = SVG('text',{x:x+bw/2,y:H-pad.b-h-6,'text-anchor':'middle','font-size':12,fill:'var(--ink)'});
    vlab.textContent = v; svg.appendChild(vlab);
  }
  const ttl = SVG('text',{x:pad.l, y:pad.t-6,'font-size':12,fill:'var(--blue)','font-style':'italic'});
  ttl.textContent = `r_k(${n})  for  k = 1, 2, 3, 4, 8`;
  svg.appendChild(ttl);
}
input.addEventListener('input', render);
render();

