const svg = $('#jtp-svg'), Nin = $('#jtp-N'), Nv = $('#jtp-Nv'), out = $('#jtp-out');

// We work in the variable u = q^{1/2}.  Then q^n = u^{2n} and q^{n-1/2} = u^{2n-1}.
// Coefficients of polynomials/series are arrays a[i] = coefficient of u^i, up to degree D.
const D = 30;

function zeros(){ return new Array(D+1).fill(0); }

function mul(A,B){
  const C = zeros();
  for(let i=0;i<=D;i++){
    if(!A[i]) continue;
    for(let j=0;j+i<=D;j++){
      if(!B[j]) continue;
      C[i+j] += A[i]*B[j];
    }
  }
  return C;
}

// series (1 - u^k) as polynomial
function oneMinusU(k){
  const p = zeros(); p[0] = 1;
  if(k<=D) p[k] = -1;
  return p;
}
// series (1 + u^k)
function onePlusU(k){
  const p = zeros(); p[0] = 1;
  if(k<=D) p[k] = 1;
  return p;
}

function partialSum(N){
  const S = zeros();
  for(let n=-N;n<=N;n++){
    const e = n*n;  // exponent of u
    if(e<=D) S[e] += 1;
  }
  return S;
}
function partialProduct(N){
  let P = zeros(); P[0] = 1;
  for(let n=1;n<=N;n++){
    P = mul(P, oneMinusU(2*n));                // (1 - u^{2n})
    P = mul(P, onePlusU(2*n-1));                // (1 + u^{2n-1}) -- twice
    P = mul(P, onePlusU(2*n-1));
  }
  return P;
}

function render(){
  const N = parseInt(Nin.value,10);
  Nv.textContent = `N = ${N}`;
  const S = partialSum(N);
  const P = partialProduct(N);

  svg.innerHTML='';
  const W=620,H=270, pad={l:40,r:16,t:18,b:40};
  const cols = D+1;
  const cw = (W-pad.l-pad.r)/cols;
  // we display |coef| with log-ish scale because coefficients can be 0,1,2
  const maxV = Math.max(3, ...S.map(Math.abs), ...P.map(Math.abs));

  svg.appendChild(SVG('line',{x1:pad.l,y1:H-pad.b,x2:W-pad.r,y2:H-pad.b,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:pad.l,y1:pad.t,x2:pad.l,y2:H-pad.b,stroke:'var(--line)'}));

  for(let i=0;i<=D;i++){
    const x = pad.l + i*cw;
    const hs = (Math.abs(S[i])/maxV) * (H-pad.t-pad.b);
    const hp = (Math.abs(P[i])/maxV) * (H-pad.t-pad.b);
    if(S[i]!==0){
      svg.appendChild(SVG('rect',{x:x+1, y:H-pad.b-hs, width:Math.max(1,cw/2-1), height:hs,
        fill: S[i]>0 ? 'var(--blue)':'var(--pink)', opacity:0.85}));
    }
    if(P[i]!==0){
      svg.appendChild(SVG('rect',{x:x+cw/2, y:H-pad.b-hp, width:Math.max(1,cw/2-1), height:hp,
        fill: P[i]>0 ? 'var(--yellow)':'var(--pink)', opacity:0.85}));
    }
    if(i%4===0){
      const t = SVG('text',{x:x+cw/2,y:H-pad.b+14,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
      t.textContent = i; svg.appendChild(t);
    }
  }
  // legend
  svg.appendChild(SVG('rect',{x:W-pad.r-170,y:pad.t,width:10,height:10,fill:'var(--blue)'}));
  const tL1 = SVG('text',{x:W-pad.r-154,y:pad.t+9,'font-size':11,fill:'var(--ink)'}); tL1.textContent='sum (truncated)'; svg.appendChild(tL1);
  svg.appendChild(SVG('rect',{x:W-pad.r-170,y:pad.t+16,width:10,height:10,fill:'var(--yellow)'}));
  const tL2 = SVG('text',{x:W-pad.r-154,y:pad.t+25,'font-size':11,fill:'var(--ink)'}); tL2.textContent='product (truncated)'; svg.appendChild(tL2);

  const xl = SVG('text',{x:(W+pad.l-pad.r)/2, y:H-6, 'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
  xl.textContent = 'exponent of u = q^(1/2)'; svg.appendChild(xl);

  // summary
  const first = [];
  for(let i=0;i<=Math.min(12,D);i++){
    first.push(`[u^${i}] sum=${S[i]} prod=${P[i]}${S[i]===P[i]?'':' ←disagree'}`);
  }
  out.textContent = 'first dozen coefficients:\n  ' + first.join('\n  ');
}
Nin.addEventListener('input', render);
render();

