const svg = $('#eta-svg'), Kin = $('#eta-K'), Kv = $('#eta-Kv'), out = $('#eta-out');

// Known Ramanujan tau
const TAU = [0, 1, -24, 252, -1472, 4830, -6048, -16744, 84480, -113643,
  -115920, 534612, -370944, -577738, 401856, 1217160, 987136, -6905934,
  2727432, 10661420, -7109760];

const D = 16; // we'll compare up to q^16

function zeros(){ return new Array(D+1).fill(0); }
function mul(A,B){
  const C = zeros();
  for(let i=0;i<=D;i++){
    if(!A[i]) continue;
    for(let j=0;j+i<=D;j++){
      if(!B[j]) continue;
      C[i+j] += A[i]*B[j];
    }
  }
  return C;
}
function oneMinusQn(n){
  const p = zeros(); p[0] = 1;
  if(n<=D) p[n] = -1;
  return p;
}

function etaPowerExpansion(K){
  // first compute P = prod_{n=1..K} (1 - q^n)
  let P = zeros(); P[0] = 1;
  for(let n=1;n<=K;n++) P = mul(P, oneMinusQn(n));
  // now raise to 24th power; but our series starts at q^0, so this gives
  // (prod (1-q^n))^24.   Delta(tau) = q · that.  So coefficient of q^m in Delta
  // is coefficient of q^{m-1} in P^24.
  let R = zeros(); R[0]=1;
  for(let i=0;i<24;i++) R = mul(R,P);
  // shift by 1 for the q^(1/24)^24 = q factor
  const Delta = zeros();
  for(let m=1;m<=D;m++) Delta[m] = R[m-1];
  return Delta;
}

function render(){
  const K = parseInt(Kin.value,10);
  Kv.textContent = `K = ${K}`;
  const Delta = etaPowerExpansion(K);

  svg.innerHTML='';
  const W=620,H=240,pad={l:50,r:16,t:20,b:38};
  // log-ish scale because |tau(n)| grows fast
  const allV = [];
  for(let n=1;n<=D;n++){ allV.push(Math.abs(Delta[n])); allV.push(Math.abs(TAU[n]||0)); }
  const maxV = Math.max(10, ...allV);
  const scale = v => Math.log(1+Math.abs(v))/Math.log(1+maxV);

  svg.appendChild(SVG('line',{x1:pad.l,y1:H-pad.b,x2:W-pad.r,y2:H-pad.b,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:pad.l,y1:pad.t,x2:pad.l,y2:H-pad.b,stroke:'var(--line)'}));

  const cw = (W-pad.l-pad.r)/D;
  for(let n=1;n<=D;n++){
    const x = pad.l + (n-1)*cw;
    const a = Delta[n], b = TAU[n]||0;
    const ha = scale(a)*(H-pad.t-pad.b);
    const hb = scale(b)*(H-pad.t-pad.b);
    // eta^24 bar (left half), tau bar (right half)
    const midY = H - pad.b;
    if(a!==0){
      const h = ha;
      const top = a>0 ? midY - h : midY;
      svg.appendChild(SVG('rect',{x:x+1,y:top,width:Math.max(1,cw/2-1),height:h,
        fill: a>0?'var(--blue)':'var(--pink)', opacity:0.9}));
    }
    if(b!==0){
      const h = hb;
      const top = b>0 ? midY - h : midY;
      svg.appendChild(SVG('rect',{x:x+cw/2,y:top,width:Math.max(1,cw/2-1),height:h,
        fill: b>0?'var(--yellow)':'var(--pink)', opacity:0.9}));
    }
    if(n%2===1){
      const t = SVG('text',{x:x+cw/2,y:H-pad.b+14,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
      t.textContent = n; svg.appendChild(t);
    }
  }
  // legend
  svg.appendChild(SVG('rect',{x:W-pad.r-160,y:pad.t,width:10,height:10,fill:'var(--blue)'}));
  const t1 = SVG('text',{x:W-pad.r-144,y:pad.t+9,'font-size':11,fill:'var(--ink)'}); t1.textContent='η^24 (truncated)'; svg.appendChild(t1);
  svg.appendChild(SVG('rect',{x:W-pad.r-160,y:pad.t+16,width:10,height:10,fill:'var(--yellow)'}));
  const t2 = SVG('text',{x:W-pad.r-144,y:pad.t+25,'font-size':11,fill:'var(--ink)'}); t2.textContent='Ramanujan τ(n)'; svg.appendChild(t2);

  // zero line
  svg.appendChild(SVG('line',{x1:pad.l,y1:H-pad.b,x2:W-pad.r,y2:H-pad.b,stroke:'var(--line)'}));

  const rows = [];
  rows.push('n   η^24 coeff      τ(n)            match?');
  for(let n=1;n<=Math.min(10,D);n++){
    const a = Delta[n], b = TAU[n]||0;
    const ok = a===b ? 'OK' : (K<n+2 ? '(need larger K)' : 'DIFF');
    rows.push(`${n.toString().padStart(2,' ')}  ${String(a).padStart(12,' ')}   ${String(b).padStart(12,' ')}   ${ok}`);
  }
  out.textContent = rows.join('\n');
}
Kin.addEventListener('input', render);
render();

