const svg = $('#lat-svg'), out = $('#lat-out');
const btns = $$('#w-lat [data-lat]');

// lattices: each is a function that returns {vectors:[ [x,y,|v|^2], ...], name, counts: {m:n}}
function buildZ2(B){
  const vs = [];
  for(let a=-B;a<=B;a++) for(let b=-B;b<=B;b++){
    vs.push([a,b,a*a+b*b]);
  }
  return vs;
}
function buildA2(B){
  // basis: e1=(1,0), e2=(1/2, sqrt(3)/2).  Inner product is standard, giving norm^2 = a^2+ab+b^2.
  const vs = [];
  for(let a=-B;a<=B;a++) for(let b=-B;b<=B;b++){
    const x = a + b*0.5;
    const y = b*Math.sqrt(3)/2;
    const n = a*a + a*b + b*b;
    vs.push([x,y,n]);
  }
  return vs;
}
function buildD4proj(B){
  // D4 = { (x1,x2,x3,x4) ∈ Z^4 : x1+x2+x3+x4 even }
  // project to 2D by (x1+x3, x2+x4) (not an isometry but good for visualization).
  // But for the theta series we use the true 4D norm.
  const vs = [];
  for(let a=-B;a<=B;a++) for(let b=-B;b<=B;b++) for(let c=-B;c<=B;c++) for(let d=-B;d<=B;d++){
    if(((a+b+c+d) & 1) !== 0) continue;
    const x = a + c*0.6;
    const y = b + d*0.6;
    const n = a*a+b*b+c*c+d*d;
    vs.push([x,y,n]);
  }
  return vs;
}

const LATS = {
  'Z2': {name:'Z²', vectors:buildZ2(6), scale:20,
    info:'basis (1,0),(0,1);  norm² = a²+b²'},
  'A2': {name:'A₂ (hex)', vectors:buildA2(7), scale:22,
    info:'basis (1,0),(1/2,√3/2);  norm² = a²+ab+b²'},
  'D4': {name:'D₄', vectors:buildD4proj(3), scale:20,
    info:'even-sum lattice in Z⁴; displayed via oblique 2D projection'}
};

function render(key){
  svg.innerHTML='';
  const L = LATS[key];
  // Count multiplicities by squared length (integer)
  const cnt = {};
  for(const v of L.vectors){
    const m = v[2];
    cnt[m] = (cnt[m]||0)+1;
  }
  const lengths = Object.keys(cnt).map(Number).sort((a,b)=>a-b);

  // Left half: draw lattice
  const W=620, H=320, leftW = 300;
  const cx = 150, cy = H/2;
  const s = L.scale;

  // axes
  svg.appendChild(SVG('line',{x1:10,y1:cy,x2:leftW-10,y2:cy,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)'}));

  // first few shells with distinct colors
  const PALETTE = ['var(--yellow)','var(--green)','var(--cyan)','var(--pink)','var(--violet)','var(--blue)'];

  // show origin ring guides for first few nonzero shells
  const firstShells = lengths.filter(m=>m>0).slice(0,5);
  for(let i=0;i<firstShells.length;i++){
    const m = firstShells[i];
    const r = Math.sqrt(m)*s;
    if(r > leftW/2) continue;
    svg.appendChild(SVG('circle',{cx,cy,r, fill:'none', stroke:PALETTE[i],'stroke-width':0.7,'stroke-dasharray':'2 3',opacity:0.55}));
  }

  for(const v of L.vectors){
    const [x,y,m] = v;
    const px = cx + x*s, py = cy - y*s;
    if(px<5 || px>leftW-5 || py<15 || py>H-15) continue;
    let color = 'var(--mute)';
    const idx = firstShells.indexOf(m);
    if(m===0) color = '#fff';
    else if(idx>=0) color = PALETTE[idx];
    const rr = m===0?3.5:2.5;
    svg.appendChild(SVG('circle',{cx:px,cy:py,r:rr,fill:color,opacity:0.95}));
  }

  // Right half: theta series coefficients
  const rightX = 330;
  const rightW = W-rightX-12;
  const maxM = Math.min(10, lengths[lengths.length-1]);
  const shown = [];
  for(let m=0;m<=maxM;m++) shown.push([m, cnt[m]||0]);
  const maxV = Math.max(1, ...shown.map(p=>p[1]));
  const scale = v => Math.log(1+v)/Math.log(1+maxV);

  const barAreaH = 220, barAreaTop = 40;
  const bw = rightW/(shown.length);
  svg.appendChild(SVG('line',{x1:rightX, y1:barAreaTop+barAreaH, x2:rightX+rightW, y2:barAreaTop+barAreaH, stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:rightX, y1:barAreaTop, x2:rightX, y2:barAreaTop+barAreaH, stroke:'var(--line)'}));

  for(let i=0;i<shown.length;i++){
    const [m,v] = shown[i];
    const x = rightX + i*bw;
    const h = scale(v)*barAreaH;
    if(v>0){
      let color = 'var(--yellow)';
      const idx = firstShells.indexOf(m);
      if(idx>=0) color = PALETTE[idx];
      if(m===0) color = '#fff';
      svg.appendChild(SVG('rect',{x:x+2,y:barAreaTop+barAreaH-h,width:Math.max(1,bw-4),height:h,fill:color,opacity:0.9}));
    }
    const t = SVG('text',{x:x+bw/2,y:barAreaTop+barAreaH+14,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
    t.textContent = m; svg.appendChild(t);
    if(v>0){
      const t2 = SVG('text',{x:x+bw/2,y:barAreaTop+barAreaH-h-4,'text-anchor':'middle','font-size':10,fill:'var(--ink)'});
      t2.textContent = v; svg.appendChild(t2);
    }
  }
  const tx = SVG('text',{x:rightX+rightW/2, y:barAreaTop+barAreaH+30, 'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
  tx.textContent = 'squared length m  (coefficient of q^(m/2))'; svg.appendChild(tx);

  const ttl = SVG('text',{x:rightX, y:barAreaTop-12,'font-size':12,fill:'var(--blue)','font-style':'italic'});
  ttl.textContent = `Θ_${L.name}(τ)`; svg.appendChild(ttl);

  // text summary
  const terms = [];
  terms.push(`Θ_{${L.name}}(τ) = `);
  let first = true;
  for(const [m,v] of shown){
    if(v===0) continue;
    if(first){ terms.push(`${v}${m===0?'':' q^('+m+'/2)'}`); first=false; }
    else terms.push(` + ${v} q^(${m}/2)`);
  }
  terms.push(' + …');
  out.textContent = `${L.info}\n${terms.join('')}`;
}

btns.forEach(b => b.addEventListener('click', ()=>{
  btns.forEach(x=>x.classList.remove('active'));
  b.classList.add('active');
  render(b.dataset.lat);
}));
render('Z2');

